module func6(clk, reset, in, out);
    input clk, reset, in;
    output out;
    reg prev_in, reg2;
    always @ (posedge clk)
        if (reset)
          begin
            prev_in <= 0; reg2 <= 0;
          end
        else
          begin
            reg2 <= prev_in; prev_in <= in;
          end
    assign out = {reg2,prev_in}==2'b01 ? 1 : 0;
endmodule
